class Solution:
    def findTilt(self, root):
        self.total = 0
        def dfs(node):
            if node is None:
                return 0
            ls = dfs(node.left)
            rs = dfs(node.right)
            self.total += abs(ls - rs)
            return ls + rs + node.val
        dfs(root)
        return self.total

