var findTilt = function(root) {
    let total = 0;
    const dfs = (node) => {
        if (node === null) return 0;
        const ls = dfs(node.left);
        const rs = dfs(node.right);
        total += Math.abs(ls - rs);
        return ls + rs + node.val;
    };
    dfs(root);
    return total;
};
